// Function to wait a bit
async function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// Function to use the right selector type
async function findElement(driver, selector) {
  if (!selector) return null;

  switch (selector.type) {
    case 'css':
      return await driver.findElement(By.css(selector.value));
    case 'id':
      return await driver.findElement(By.id(selector.value));
    case 'xpath':
      return await driver.findElement(By.xpath(selector.value));
    case 'linkText':
      return await driver.findElement(By.linkText(selector.value));
    default:
      throw new Error(`Unknown selector type: ${selector.type}`);
  }
}

async function processUlsterCountyRecord(driver, record) {
  try {
    const sbl = record.fields.SBL;
    if (!sbl) {
      return { ...record, error: 'No SBL provided' };
    }

    console.log(`Processing record with SBL: ${sbl}`);
    const sblParts = sbl.split('-');

    // Navigate to the base URL if it's the first record or URL has changed
    await driver.get(countyConfig.baseUrl);
    await sleep(2000);

    // Click on the Public Access link if present
    try {
      const publicAccessLink = await findElement(driver, countyConfig.selectors.publicAccess);
      if (publicAccessLink) {
        console.log('Clicking on Public Access link');
        await publicAccessLink.click();
        await sleep(2000);
      }
    } catch (err) {
      console.log('Public Access link not found, continuing...');
    }

    // Check for and click the agreement button if present
    try {
      const agreeButton = await findElement(driver, countyConfig.selectors.agreement);
      if (agreeButton) {
        console.log('Clicking on I Agree button');
        await agreeButton.click();
        await sleep(2000);
      }
    } catch (err) {
      console.log('Agreement button not found, continuing...');
    }

    // Wait for and select the municipality dropdown
    console.log('Selecting municipality...');
    const municipalitySelect = await findElement(driver, countyConfig.selectors.municipalitySelect);
    if (municipalitySelect) {
      await municipalitySelect.sendKeys(countyConfig.defaultSwis || sblParts[0]);
      await sleep(1000);
    }

    // Fill in the SBL parts
    console.log('Filling in SBL fields...');
    const swisField = await findElement(driver, countyConfig.selectors.swisField);
    if (swisField) {
      await swisField.sendKeys(sblParts[0]);
      await sleep(500);
    }

    const sectionField = await findElement(driver, countyConfig.selectors.sectionField);
    if (sectionField) {
      await sectionField.sendKeys(sblParts[1]);
      await sleep(500);
    }

    const blockField = await findElement(driver, countyConfig.selectors.blockField);
    if (blockField) {
      await blockField.sendKeys(sblParts[2]);
      await sleep(500);
    }

    const lotField = await findElement(driver, countyConfig.selectors.lotField);
    if (lotField) {
      await lotField.sendKeys(sblParts[3]);
      await sleep(1000);
    }

    // Click search button
    console.log('Clicking search button...');
    const searchButton = await findElement(driver, countyConfig.selectors.searchButton);
    if (searchButton) {
      await searchButton.click();
      await sleep(3000);
    }

    // Extract property information
    let propertyInfo = {};
    try {
      // Wait for results to load
      await driver.wait(until.elementLocated(By.css(countyConfig.selectors.resultsTable.value)), 10000);

      // Extract information
      const ownerElement = await findElement(driver, countyConfig.selectors.ownerInfo);
      if (ownerElement) {
        propertyInfo.owner = await ownerElement.getText();
      }

      const addressElement = await findElement(driver, countyConfig.selectors.addressInfo);
      if (addressElement) {
        propertyInfo.address = await addressElement.getText();
      }

      const assessmentElement = await findElement(driver, countyConfig.selectors.assessmentInfo);
      if (assessmentElement) {
        propertyInfo.assessment = await assessmentElement.getText();
      }

      // Take a screenshot for verification
      propertyInfo.screenshot = await driver.takeScreenshot();

      return {
        ...record,
        fields: {
          ...record.fields,
          Property_Owner: propertyInfo.owner,
          Property_Address: propertyInfo.address,
          Assessed_Value: propertyInfo.assessment,
          Last_Updated: new Date().toISOString()
        },
        success: true
      };
    } catch (error) {
      console.error('Error extracting property information:', error);
      return {
        ...record,
        error: `Failed to extract property information: ${error.message}`
      };
    }
  } catch (error) {
    console.error('Processing error:', error);
    return { ...record, error: error.message };
  }
}

